  pairing_logic = '{"pairs_well_before":["throwing_skill","medicine_ball_output","strength_training","sport_practice"],"pairs_well_after":["general_warmup","breathing_or_rib_stack","hip_and_t_spine_access"],"good_for_sessions":["overhead_prep","sprint_prep","general_warmup","throwing_athlete_preparation"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["sharp shoulder, elbow, back, hip, or wrist pain","mechanics already degraded from fatigue","throwing volume is being deliberately deloaded and the exercise adds the same stress"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Kinetic-chain reviews of overhead throwing and return-to-sport decision-making.","Resistance-training and medicine-ball training literature on throwing velocity and power transfer.","Shoulder-injury prevention and kinetic-chain strengthening literature for overhead athletes."],"internal_notes":["Use as support work; do not let the exercise compete with throwing skill quality or planned throwing-volume management."]}'::jsonb,
  updated_at = now()
WHERE slug = 'forearm-flexor-extensor-eccentric';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'forearm_flexor_extensor_eccentric_throwers',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = FALSE,
  fatigue_sensitivity = 3,
  fatigue_cost = 2,
  technical_complexity = 3,
  impact_level = 0,
  intensity_ceiling = 'moderate',
  notes = ''
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'resilience'
JOIN coaching.phase_order_slot pos ON pos.key = 'forearm_flexor_extensor_eccentric_throwers' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'forearm-flexor-extensor-eccentric';

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'reps',
  default_sets = 2,
  default_reps = 6,
  default_load_note = '6-10',
  default_work_seconds = 35,
  default_rest_seconds = 45,
  est_seconds_per_set = 85,
  default_rpe_min = 3,
  default_rpe_max = 6,
  session_volume_min = NULL,
  session_volume_max = NULL
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'forearm-flexor-extensor-eccentric';

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = FALSE,
  weekly_max_frequency = 3,
  minimum_hours_between_hard_exposures = 24,
  counts_as_high_intensity = FALSE,
  counts_as_high_impact = FALSE,
  counts_as_neural = FALSE,
  counts_as_tissue_stress = TRUE,
  counts_as_conditioning = FALSE
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'forearm-flexor-extensor-eccentric';

UPDATE coaching.exercise_safety_profile s SET
  risk_level = 1,
  impact_level = 0,
  requires_spotting = FALSE,
  requires_coach_supervision = 'optional',
  readiness_checks = ARRAY['Pain-free warm-up range.', 'No sharp shoulder or elbow symptoms today.', 'Athlete can demonstrate the base position without compensation.']::text[],
  contraindications = ARRAY['Acute shoulder, elbow, wrist, back, hip, or knee injury unless cleared and modified.', 'Recent spike in throwing volume, soreness, or loss of throwing velocity without coach/medical review.']::text[],
  common_substitutions = ARRAY['lighter band', 'isometric hold', 'shorter range pain-free variation']::text[]
FROM coaching.exercise e
WHERE s.exercise_id = e.id AND e.slug = 'forearm-flexor-extensor-eccentric';

