-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Supports kinetic-chain throwing performance: force creation, transfer, arm expression, deceleration, and tissue tolerance.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('half-kneeling-t-spine-rotation-reach', 'Throwing is a linked kinetic-chain skill. Half-Kneeling T-Spine Rotation Reach targets a piece of that chain so the athlete can create force, transfer force, decelerate, or maintain joint position without relying only on the arm.', 'Belongs in Prepare & Access because the goal is to create usable range, low-threat activation, and clean positional options before throwing, lifting, or higher-intent work.', 'Use on throwing or lifting days only when it supports the main goal. Keep high-intent work early and fresh; place strength after skill/output unless it is the primary training block; use resilience work after main throwing or in lower-intensity support sessions.', 'Do not turn this into a long mobility circuit or fatigue block. Keep it crisp and stop if range is being forced, breath is held, or positions become sloppy.', 'Regress range, load, speed, distance, partner pressure, cue complexity, or total reps before removing quality. Progress only after the athlete owns pain-free mechanics and recovery between reps.'),
